// lru.hpp — header-only LRU cache (C++17)
// Key/value: int64_t. O(1) average get/put via unordered_map + list.
#ifndef LRU_HPP
#define LRU_HPP

#include <cstdint>
#include <list>
#include <optional>
#include <unordered_map>
#include <stdexcept>
#include <utility>

class LRUCache {
public:
    using key_type   = std::int64_t;
    using value_type = std::int64_t;

    explicit LRUCache(std::size_t capacity) : capacity_(capacity) {
        if (capacity_ == 0) {
            throw std::invalid_argument("LRUCache capacity must be > 0");
        }
    }

    // Return value and mark most-recently-used; std::nullopt if absent.
    std::optional<value_type> get(key_type key) {
        auto it = map_.find(key);
        if (it == map_.end()) {
            return std::nullopt;
        }
        // Move node to front (most-recently-used) in O(1).
        order_.splice(order_.begin(), order_, it->second);
        return it->second->second;
    }

    // Insert/update; mark most-recently-used. Evict LRU first if a NEW key
    // would exceed capacity. Updating an existing key does NOT evict.
    void put(key_type key, value_type value) {
        auto it = map_.find(key);
        if (it != map_.end()) {
            // Update existing: refresh recency, no eviction.
            it->second->second = value;
            order_.splice(order_.begin(), order_, it->second);
            return;
        }
        // New key: evict LRU first if at capacity.
        if (map_.size() >= capacity_) {
            const auto& lru = order_.back();
            map_.erase(lru.first);
            order_.pop_back();
        }
        order_.emplace_front(key, value);
        map_.emplace(key, order_.begin());
    }

    std::size_t len() const noexcept { return map_.size(); }

    std::size_t capacity() const noexcept { return capacity_; }

private:
    using list_type = std::list<std::pair<key_type, value_type>>;

    std::size_t capacity_;
    list_type   order_;  // front = MRU, back = LRU
    std::unordered_map<key_type, typename list_type::iterator> map_;
};

#endif // LRU_HPP

// tests.cpp — 7 unit tests for LRUCache (no external deps).
#include "lru.hpp"

#include <cstdint>
#include <cstdio>
#include <cstdlib>

static int g_failures = 0;

static void report(const char* name, bool ok) {
    std::printf("[%s] %s\n", ok ? "PASS" : "FAIL", name);
    if (!ok) ++g_failures;
}

// Simple check helper: accumulates into a local ok flag.
#define CHECK(cond) do { if (!(cond)) { ok = false; \
    std::printf("    check failed: %s (line %d)\n", #cond, __LINE__); } } while (0)

int main() {
    // 1. put/get basic hit.
    {
        bool ok = true;
        LRUCache c(2);
        c.put(1, 100);
        auto v = c.get(1);
        CHECK(v.has_value());
        CHECK(v.value() == 100);
        report("1. put/get basic hit", ok);
    }

    // 2. get on missing key returns not-found.
    {
        bool ok = true;
        LRUCache c(2);
        c.put(1, 100);
        auto v = c.get(42);
        CHECK(!v.has_value());
        report("2. missing key returns not-found", ok);
    }

    // 3. Update existing key changes value, no eviction.
    {
        bool ok = true;
        LRUCache c(2);
        c.put(1, 100);
        c.put(2, 200);
        c.put(1, 999);            // update, must not evict
        CHECK(c.len() == 2);
        CHECK(c.get(1).value() == 999);
        CHECK(c.get(2).value() == 200);
        report("3. update changes value, no eviction", ok);
    }

    // 4. Exceeding capacity evicts the LRU key.
    {
        bool ok = true;
        LRUCache c(2);
        c.put(1, 100);
        c.put(2, 200);
        c.put(3, 300);            // evicts key 1 (LRU)
        CHECK(c.len() == 2);
        CHECK(!c.get(1).has_value());
        CHECK(c.get(2).value() == 200);
        CHECK(c.get(3).value() == 300);
        report("4. exceeding capacity evicts LRU", ok);
    }

    // 5. get() refreshes recency (got key survives subsequent eviction).
    {
        bool ok = true;
        LRUCache c(2);
        c.put(1, 100);
        c.put(2, 200);
        (void)c.get(1);           // 1 becomes MRU; 2 is now LRU
        c.put(3, 300);            // evicts 2, not 1
        CHECK(c.get(1).value() == 100);
        CHECK(!c.get(2).has_value());
        CHECK(c.get(3).value() == 300);
        report("5. get() refreshes recency", ok);
    }

    // 6. Capacity 1 edge case.
    {
        bool ok = true;
        LRUCache c(1);
        c.put(1, 100);
        CHECK(c.get(1).value() == 100);
        c.put(2, 200);            // evicts 1
        CHECK(!c.get(1).has_value());
        CHECK(c.get(2).value() == 200);
        CHECK(c.len() == 1);
        report("6. capacity 1 edge case", ok);
    }

    // 7. Overwrite refreshes recency.
    {
        bool ok = true;
        LRUCache c(2);
        c.put(1, 100);
        c.put(2, 200);
        c.put(1, 111);            // overwrite -> 1 becomes MRU, 2 is LRU
        c.put(3, 300);            // evicts 2
        CHECK(c.get(1).value() == 111);
        CHECK(!c.get(2).has_value());
        CHECK(c.get(3).value() == 300);
        report("7. overwrite refreshes recency", ok);
    }

    if (g_failures == 0) {
        std::printf("\nAll tests passed.\n");
        return 0;
    }
    std::printf("\n%d test(s) FAILED.\n", g_failures);
    return 1;
}

// bench.cpp — exact benchmark from SPEC.md.
#include "lru.hpp"

#include <chrono>
#include <cstdint>
#include <cstdio>

int main() {
    constexpr std::size_t   CAPACITY = 10000;
    constexpr std::uint64_t TOTAL_OPS = 1000000;
    constexpr std::uint64_t KEYSPACE = 20000;

    // LCG constants (wrapping unsigned 64-bit).
    constexpr std::uint64_t A = 6364136223846793005ULL;
    constexpr std::uint64_t C = 1442695040888963407ULL;

    auto run_pass = [&](bool timed) -> std::pair<std::uint64_t, double> {
        LRUCache cache(CAPACITY);
        std::uint64_t state = 42;
        std::uint64_t checksum = 0; // wrapping u64 sum of successful-get values.

        auto start = std::chrono::steady_clock::now();
        for (std::uint64_t i = 0; i < TOTAL_OPS; ++i) {
            state = A * state + C;                       // wrapping
            std::uint64_t key = (state >> 33) % KEYSPACE;
            if ((state & 1ULL) == 0) {
                auto v = cache.get(static_cast<std::int64_t>(key));
                if (v.has_value()) {
                    checksum += static_cast<std::uint64_t>(v.value()); // wrapping
                }
            } else {
                cache.put(static_cast<std::int64_t>(key),
                          static_cast<std::int64_t>(key));
            }
        }
        auto end = std::chrono::steady_clock::now();
        double elapsed = std::chrono::duration<double>(end - start).count();
        (void)timed;
        // Return checksum and elapsed; also stash final size via static hack-free path.
        // We need final size too; recompute below by returning through struct-like pair
        // is insufficient, so print inside for timed pass instead.
        if (timed) {
            std::printf("final cache size: %zu\n", cache.len());
        }
        return {checksum, elapsed};
    };

    // Warm-up pass (not timed).
    run_pass(false);

    // Timed pass.
    auto [checksum, elapsed] = run_pass(true);

    double ops_per_sec = static_cast<double>(TOTAL_OPS) / elapsed;

    std::printf("total ops:   %llu\n", static_cast<unsigned long long>(TOTAL_OPS));
    std::printf("elapsed sec: %.6f\n", elapsed);
    std::printf("ops/sec:     %.0f\n", ops_per_sec);
    std::printf("checksum:    %llu\n", static_cast<unsigned long long>(checksum));

    return 0;
}
